// 1. Obtenemos el texto del mensaje
const inputMensaje = $input.item.json.mensaje || "";

// 2. Función de extracción ULTRA-PRECISA
const extraer = (etiqueta) => {
  /* Explicación del Regex:
     - [^a-zA-Z0-9]* : Ignora emoticonos o símbolos antes de la etiqueta.
     - ${etiqueta}   : Busca tu palabra clave.
     - [^:]* : Ignora cualquier cosa que no sea ":" (como emoticonos pegados).
     - :?\s* : Busca los dos puntos opcionales y espacios.
     - ([^\\\n\r|]*) : CAPTURA: Todo lo que NO sea un salto de línea (\n), un retorno (\r) o un separador (|).
  */
  const regex = new RegExp(`(?:[^a-zA-Z0-9]*)${etiqueta}[^:]*:?\\s*([^\\\\\\n\\r|]*)`, 'i');
  const match = inputMensaje.match(regex);

  if (match && match[1]) {
    // Limpiamos espacios y posibles restos de n8n
    return match[1].split('\\n')[0].trim(); 
  }
  return null;
};

// 3. Extraemos los campos usando solo las palabras clave
const datos = {
  proveedor: extraer('Proveedor'),
  numero: extraer('Nº Factura') || extraer('Número'),
  fecha: extraer('Fecha'),
  subtotal: extraer('Subtotal'),
  impuestos: extraer('Impuestos'),
  total: extraer('TOTAL'),
  pago: extraer('Forma de pago') || extraer('Pago'),
  estado: extraer('Estado'),
  moneda: extraer('Moneda')
};

// 4. Limpiador final de caracteres basura
const clean = (text) => {
  if (!text || text.toLowerCase() === "null" || text === "N/A") return 'No disponible';
  return text.toString()
    .replace(/[{}*"\\]/g, '') // Elimina llaves, asteriscos, comillas y barras
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') // Escape HTML
    .trim();
};

// 5. Construcción del mensaje HTML limpio para Telegram
const mensajeHTML = `
<b>🔔 NOTIFICACIÓN DE FACTURA</b>

📄 <b>Información General</b>
━━━━━━━━━━━━━━━━━━
🏢 <b>Proveedor:</b> ${clean(datos.proveedor)}
🔢 <b>Nº Factura:</b> ${clean(datos.numero)}
📅 <b>Fecha:</b> ${clean(datos.fecha)}

💰 <b>Resumen Económico</b>
━━━━━━━━━━━━━━━━━━
<b>Subtotal:</b> ${clean(datos.subtotal)}
<b>IVA/Impuestos:</b> ${clean(datos.impuestos)}
✅ <b>TOTAL:</b> <code>${clean(datos.total)} ${clean(datos.moneda)}</code>

📌 <b>Detalles Adicionales</b>
━━━━━━━━━━━━━━━━━━
💳 <b>Método de Pago:</b> ${clean(datos.pago)}
🚦 <b>Estado:</b> <i>${clean(datos.estado)}</i>
`.trim();

return {
  mensaje: mensajeHTML
};
